const CUSTOMER_POOL = [
  { id: 'CUST_CRITICAL_001', name: 'Vikram Singh',   city: 'Jaipur',     region: 'North', salary: 28000,  segment: 'gig_worker',    creditScore: 520 },
  { id: 'CUST_CRITICAL_002', name: 'Anjali Gupta',   city: 'Lucknow',    region: 'North', salary: 24000,  segment: 'gig_worker',    creditScore: 545 },
  { id: 'CUST_CRITICAL_003', name: 'Ravi Shankar',   city: 'Patna',      region: 'East',  salary: 22000,  segment: 'farmer',        creditScore: 498 },
  { id: 'CUST_WATCH_001',    name: 'Karthik Reddy',  city: 'Hyderabad',  region: 'South', salary: 48000,  segment: 'salaried',      creditScore: 634 },
  { id: 'CUST_WATCH_002',    name: 'Deepa Menon',    city: 'Kochi',      region: 'South', salary: 42000,  segment: 'self_employed', creditScore: 648 },
  { id: 'CUST_WATCH_003',    name: 'Priya Sharma',   city: 'Mumbai',     region: 'West',  salary: 55000,  segment: 'salaried',      creditScore: 671 },
  { id: 'CUST_STRESSED_001', name: 'Rahul Verma',    city: 'Delhi',      region: 'North', salary: 40000,  segment: 'gig_worker',    creditScore: 603 },
  { id: 'CUST_STABLE_001',   name: 'Arjun Nair',     city: 'Bangalore',  region: 'South', salary: 120000, segment: 'salaried',      creditScore: 764 },
  { id: 'CUST_STABLE_002',   name: 'Meera Iyer',     city: 'Chennai',    region: 'South', salary: 65000,  segment: 'salaried',      creditScore: 742 },
  { id: 'CUST_STABLE_003',   name: 'Rohit Desai',    city: 'Pune',       region: 'West',  salary: 95000,  segment: 'salaried',      creditScore: 788 }
];

const stressTxnTypes = ['lending_app', 'atm_withdrawal', 'cash_advance', 'payday_lender'];
const normalTxnTypes = ['upi_debit', 'pos_purchase', 'online_transfer', 'emi_payment'];
const stressCats = ['lending_app', 'gambling', 'payday_lender', 'cash_advance'];

const cust = CUSTOMER_POOL[Math.floor(Math.random() * CUSTOMER_POOL.length)];
const isCritical = cust.id.includes('CRITICAL');
const isWatch = cust.id.includes('WATCH') || cust.id.includes('STRESSED');

const txnType = isCritical
  ? stressTxnTypes[Math.floor(Math.random() * stressTxnTypes.length)]
  : isWatch
    ? (Math.random() > 0.5 ? stressTxnTypes[Math.floor(Math.random() * stressTxnTypes.length)] : normalTxnTypes[Math.floor(Math.random() * normalTxnTypes.length)])
    : normalTxnTypes[Math.floor(Math.random() * normalTxnTypes.length)];

const merchantCat = isCritical
  ? stressCats[Math.floor(Math.random() * stressCats.length)]
  : isWatch
    ? (Math.random() > 0.4 ? stressCats[Math.floor(Math.random() * stressCats.length)] : 'groceries')
    : ['groceries', 'fuel', 'dining', 'entertainment'][Math.floor(Math.random() * 4)];

const amount = isCritical ? Math.floor(Math.random() * 15000) + 2000 : isWatch ? Math.floor(Math.random() * 8000) + 500 : Math.floor(Math.random() * 3000) + 100;
const txnStatus = isCritical && Math.random() > 0.6 ? 'failed' : 'success';

const txn = {
  txn_id: 'TXN_' + Date.now() + '_' + Math.floor(Math.random() * 10000),
  customer_id: cust.id,
  customer_name: cust.name,
  city: cust.city,
  region: cust.region,
  segment: cust.segment,
  monthly_salary: cust.salary,
  credit_score: cust.creditScore,
  txn_type: txnType,
  merchant_category: merchantCat,
  amount: amount,
  txn_status: txnStatus,
  is_stress_signal: stressCats.includes(merchantCat) || txnStatus === 'failed',
  channel: ['mobile_app', 'web', 'branch', 'atm'][Math.floor(Math.random() * 4)],
  ingested_at: new Date().toISOString(),
  failed_autodebits_count_30d: isCritical ? Math.floor(Math.random()*5)+3 : isWatch ? Math.floor(Math.random()*3)+1 : 0,
  lending_app_txn_count_30d: isCritical ? Math.floor(Math.random()*6)+4 : isWatch ? Math.floor(Math.random()*3)+1 : 0,
  salary_delay_days: isCritical ? Math.floor(Math.random()*18)+5 : isWatch ? Math.floor(Math.random()*8) : 0,
  savings_balance_pct_change_7d: isCritical ? -(Math.random()*0.45+0.3) : isWatch ? -(Math.random()*0.2) : Math.random()*0.1,
  discretionary_spend_trend: isCritical ? 1.9+Math.random()*0.4 : isWatch ? 1.3+Math.random()*0.3 : 0.8+Math.random()*0.2,
  dti_ratio: isCritical ? 0.58+Math.random()*0.2 : isWatch ? 0.38+Math.random()*0.15 : 0.18+Math.random()*0.12,
  night_txn_ratio: isCritical ? 0.32+Math.random()*0.18 : Math.random()*0.12,
  atm_withdrawal_count_7d: isCritical ? Math.floor(Math.random()*8)+4 : isWatch ? Math.floor(Math.random()*4)+1 : Math.floor(Math.random()*2),
  pipeline_ts: Date.now(),
  source: 'CBS_SIMULATION'
};

console.log('[INGEST] ' + txn.txn_id + ' | ' + cust.name + ' | ' + txnType + ' | amt=' + amount);
return [{ json: txn }];

const txn = $('CBS Ingestion Layer').first().json;
const auth = $input.first().json;
const token = auth.access_token || '';
console.log('[AUTH] Token: ' + (token ? 'OK' : 'MISSING - will use heuristic'));
return [{ json: { ...txn, _bearer_token: token } }];

const txn = $('Attach Auth Token').first().json;
const scoreRaw = $input.first().json;

let risk_score, risk_tier, xgboost_score, lightgbm_score, tft_score, ensemble_score,
    top_shap_features, product_actions, tte_days, calibrated_pd, uplift_score,
    confidence_flag, meta_learner_used, scored_at, ml_api_used;

if (scoreRaw && scoreRaw.risk_score !== undefined) {
  // Real ML API response
  risk_score = scoreRaw.risk_score;
  risk_tier = scoreRaw.risk_tier;
  xgboost_score = scoreRaw.xgboost_score;
  lightgbm_score = scoreRaw.lightgbm_score;
  tft_score = scoreRaw.tft_score;
  ensemble_score = scoreRaw.ensemble_score || risk_score;
  top_shap_features = scoreRaw.top_shap_features || [];
  product_actions = scoreRaw.product_actions || [];
  tte_days = scoreRaw.tte_days;
  calibrated_pd = scoreRaw.calibrated_pd || null;
  uplift_score = scoreRaw.uplift_score || null;
  confidence_flag = scoreRaw.confidence_flag || 'green';
  meta_learner_used = scoreRaw.meta_learner_used || false;
  scored_at = scoreRaw.scored_at || new Date().toISOString();
  ml_api_used = true;
} else {
  // Heuristic fallback
  const isCritical = txn.customer_id.includes('CRITICAL');
  const isWatch = txn.customer_id.includes('WATCH') || txn.customer_id.includes('STRESSED');
  risk_score = isCritical ? 0.72 + Math.random()*0.2 : isWatch ? 0.42 + Math.random()*0.2 : 0.1 + Math.random()*0.2;
  risk_tier = risk_score > 0.65 ? 'critical' : risk_score > 0.35 ? 'watch' : 'stable';
  xgboost_score = risk_score + (Math.random()*0.06-0.03);
  lightgbm_score = risk_score + (Math.random()*0.06-0.03);
  tft_score = null;
  ensemble_score = risk_score;
  top_shap_features = [
    { feature: 'dti_ratio', value: txn.dti_ratio },
    { feature: 'credit_score', value: -0.3 },
    { feature: 'failed_autodebits', value: txn.failed_autodebits_count_30d * 0.1 }
  ];
  product_actions = risk_score > 0.65
    ? ['suspend_new_credit', 'escalate_to_rm', 'send_financial_counseling']
    : risk_score > 0.35
      ? ['flag_for_review', 'reduce_credit_limit', 'send_payment_reminder']
      : ['monitor_passively'];
  tte_days = risk_score > 0.65 ? Math.floor(Math.random()*15)+5 : risk_score > 0.35 ? Math.floor(Math.random()*45)+15 : null;
  calibrated_pd = risk_score * 0.9;
  uplift_score = null;
  confidence_flag = 'yellow';
  meta_learner_used = false;
  scored_at = new Date().toISOString();
  ml_api_used = false;
}

const tierIcon = { critical: '\uD83D\uDD34', watch: '\uD83D\uDFE1', stable: '\uD83D\uDFE2' }[risk_tier] || '\u26AA';
console.log('[SCORE] ' + txn.customer_name + ' | ' + tierIcon + ' ' + risk_tier.toUpperCase() + ' | score=' + risk_score.toFixed(3) + ' | ml=' + ml_api_used);

return [{ json: {
  ...txn,
  risk_score, risk_tier, xgboost_score, lightgbm_score, tft_score, ensemble_score,
  top_shap_features, product_actions, tte_days, calibrated_pd, uplift_score,
  confidence_flag, meta_learner_used, scored_at, ml_api_used
} }];

// Stable — no notification needed
const d = $input.first().json;
console.log('[STABLE] ' + d.customer_name + ' — no action needed (score=' + d.risk_score.toFixed(3) + ')');
return [{ json: { ...d, notify_status: 'no_action', channels_sent: 'none', channels_count: 0, notify_results: [] } }];

const d = $('Process Score Result').first().json;
const notifyRaw = $input.first().json;

let notify_status, channels_sent, channels_count, notify_results;

if (notifyRaw && notifyRaw.status === 'dispatched') {
  notify_status = 'dispatched';
  channels_count = notifyRaw.channels_attempted || 0;
  notify_results = notifyRaw.results || [];
  channels_sent = notify_results.filter(r => r.status === 'sent').map(r => r.channel).join('+') || 'attempted';
} else {
  notify_status = 'dispatch_error';
  channels_sent = 'error';
  channels_count = 0;
  notify_results = [];
}

console.log('[NOTIFY] ' + d.customer_name + ' | status=' + notify_status + ' | via=' + channels_sent);
return [{ json: { ...d, notify_status, channels_sent, channels_count, notify_results } }];

const d = $('Build Pipeline Summary').first().json;
console.log('[COMPLETE] event=' + d.event_id + ' | ' + d.customer_name + ' | ' + d.risk_tier.toUpperCase() + ' | score=' + d.risk_score.toFixed(3) + ' | pipeline=' + d.pipeline_run_ms + 'ms');
return [{ json: { status: 'pipeline_complete', event_id: d.event_id, customer_name: d.customer_name, risk_tier: d.risk_tier, risk_score: d.risk_score, pipeline_run_ms: d.pipeline_run_ms } }];
